1	import { supabase } from './supabase.js';
2	import { writeCounterfactuals } from './ips-engine.js';
3	import { upsertSequence, closeSequence } from './sequence-tracker.js';
4	import { backpropagateReward } from './reward-backprop.js';
5	import type { SupabaseClient } from '@supabase/supabase-js';
6	
7	// ── Shared Types ──
8	export interface OrchestratorParams {
9	    agentId: string;
10	    customerId: string;
11	    outcomeId: string;
12	    actionId: string;
13	    actionName: string;
14	    contextId: string;
15	    issueType: string;
16	    finalSuccess: boolean;
17	    finalOutcomeScore: number | null;
18	    responseMs?: number | null;
19	    episodeId?: string;
20	    businessOutcome?: string;
21	    decisionId?: string;
22	    decisionRecord?: any;
23	    signalConfidence?: number | null;
24	}
25	
26	// ── Orchestrator Main Entrypoint ──
27	export async function orchestrateOutcome(params: OrchestratorParams): Promise<void> {
28	
29	    async function taskTrustUpdate() {
30	        await updateAgentTrust(params.agentId, params.customerId, params.finalSuccess,
31	            params.actionName, params.signalConfidence ?? null);
32	    }
33	
34	    async function taskContextDrift() {
35	        await detectContextDrift(supabase, params.customerId, params.issueType, params.agentId);
36	    }
37	
38	    async function taskSilentFailure() {
39	        await detectSilentFailure(supabase, {
40	            outcome_id: params.outcomeId,
41	            customer_id: params.customerId,
42	            agent_id: params.agentId,
43	            action_id: params.actionId,
44	            action_name: params.actionName,
45	            success: params.finalSuccess,
46	            outcome_score: params.finalOutcomeScore,
47	        });
48	    }
49	
50	    async function taskCounterfactuals() {
51	        if (params.decisionRecord?.ranked_actions) {
52	            const outcomeScore = params.finalOutcomeScore ?? (params.finalSuccess ? 1.0 : 0.0);
53	            await writeCounterfactuals({
54	                decisionId: params.decisionId!,
55	                realOutcomeId: params.outcomeId,
56	                realOutcomeScore: outcomeScore,
57	                chosenActionName: params.actionName,
58	                rankedActions: params.decisionRecord.ranked_actions,
59	                contextHash: params.decisionRecord.context_hash ?? '',
60	                episodePosition: params.decisionRecord.episode_position ?? 0,
61	            });
62	        }
63	    }
64	
65	    async function taskSequence() {
66	        if (params.episodeId) {
67	            await upsertSequence({
68	                episodeId: params.episodeId,
69	                agentId: params.agentId,
70	                contextHash: params.decisionRecord?.context_hash ?? `${params.contextId}:${params.issueType}`,
71	                actionName: params.actionName,
72	                responseMs: params.responseMs ?? undefined,
73	            });
74	
75	            if (params.businessOutcome === 'resolved' || params.businessOutcome === 'failed') {
76	                const finalScore = params.finalOutcomeScore ?? (params.finalSuccess ? 1.0 : 0.0);
77	                await closeSequence({
78	                    episodeId: params.episodeId,
79	                    finalOutcome: finalScore,
80	                });
81	
82	                await backpropagateReward({
83	                    episode_id: params.episodeId,
84	                    final_outcome: finalScore,
85	                    gamma: 0.85,
86	                });
87	            }
88	        }
89	    }
90	
91	    // Trust atomicity is guaranteed by the update_trust_and_audit() RPC (migration 062),
92	    // which writes both the trust score UPDATE and audit INSERT in one DB transaction.
93	    // Surfacing trust failures as HTTP 500 to agents is counterproductive — a trust DB
94	    // issue should not block outcome logging entirely. Run all tasks via allSettled.
95	    const results = await Promise.allSettled([
96	        taskTrustUpdate(),
97	        taskContextDrift(),
98	        taskSilentFailure(),
99	        taskCounterfactuals(),
100	        taskSequence(),
101	    ]);
102	
103	    const taskNames = [
104	        'trust-update',
105	        'context-drift',
106	        'silent-failure',
107	        'counterfactuals',
108	        'sequence',
109	    ];
110	
111	    results.forEach((result, index) => {
112	        if (result.status === 'rejected') {
113	            const taskName = taskNames[index];
114	            console.error(`[orchestrator:${taskName}] failed`, {
115	                error: (result.reason as Error)?.message,
116	                outcomeId: params.outcomeId,
117	                agentId: params.agentId,
118	            });
119	        }
120	    });
121	
122	    // Non-blocking: upsert live trust score so dashboard health card
123	    // shows real data immediately (not 0 while waiting for backprop engine)
124	    upsertLiveTrustScore(params.agentId).catch((err) =>
125	        console.warn('[orchestrator] upsertLiveTrustScore failed:', (err as Error).message)
126	    );
127	}
128	
129	// ── Live Trust Score Upsert (fire-and-forget, creates row for new agents) ──
130	async function upsertLiveTrustScore(
131	    agentId: string,
132	): Promise<void> {
133	    const { data: outcomes, error } = await supabase
134	        .from('fact_outcomes')
135	        .select('success')
136	        .eq('agent_id', agentId)
137	        .eq('is_synthetic', false)
138	        .eq('is_deleted', false)
139	        .order('timestamp', { ascending: false })
140	        .limit(100);
141	
142	    if (error) {
143	        console.warn('[trust] upsertLiveTrustScore: failed to fetch outcomes:', error.message);
144	    }
145	
146	    if (error || !outcomes || outcomes.length === 0) {
147	        // Ensure zero-outcome agents stay in 'new' state with no score.
148	        // Guards against any race condition or manual call writing a stale score.
149	        await supabase
150	            .from('agent_trust_scores')
151	            .update({ trust_status: 'new', trust_score: null })
152	            .eq('agent_id', agentId)
153	            .eq('total_decisions', 0);
154	        return;
155	    }
156	
157	    const total = outcomes.length;
158	    const successes = outcomes.filter((o) => o.success).length;
159	    const rawScore = successes / total;
160	
161	    const recent = outcomes.slice(0, 10);
162	    const recentSuccesses = recent.filter((o) => o.success).length;
163	    const recentWeight = recent.length > 0 ? recentSuccesses / recent.length : rawScore;
164	    const weightedScore = Math.round(((rawScore * 0.6) + (recentWeight * 0.4)) * 10000) / 10000;
165	
166	    const consecutiveFailures = (() => {
167	        let count = 0;
168	        for (const o of outcomes) {
169	            if (!o.success) count++;
170	            else break;
171	        }
172	        return count;
173	    })();
174	
175	    // Check >= 10 before >= 5 so 'suspended' is reachable
176	    const trustStatus =
177	        consecutiveFailures >= 10 ? 'suspended' :
178	        consecutiveFailures >= 5  ? 'degraded'  :
179	        weightedScore >= 0.7      ? 'trusted'   : 'probation';
180	
181	    await supabase
182	        .from('agent_trust_scores')
183	        .upsert({
184	            agent_id: agentId,
185	            trust_score: weightedScore,
186	            trust_status: trustStatus,
187	            consecutive_failures: consecutiveFailures,
188	            total_decisions: total,
189	            updated_at: new Date().toISOString(),
190	        }, { onConflict: 'agent_id' });
191	
192	    // NOTE: No audit INSERT here. The update_trust_and_audit() RPC (called by
193	    // updateAgentTrust() for each outcome) already writes the canonical audit row.
194	    // Adding a second insert here would produce duplicate Trust History entries.
195	}
196	
197	// ── Trust Snapshot (fire-and-forget) ──────────────────────────
198	async function snapshotTrust(
199	    agentId: string,
200	    trust: { trust_score: number; trust_status: string; consecutive_failures: number },
201	    reason: 'pre_failure' | 'pre_incident' | 'manual',
202	    incidentId?: string,
203	): Promise<void> {
204	    await supabase.from('agent_trust_snapshots').insert({
205	        agent_id: agentId,
206	        trust_score: trust.trust_score,
207	        trust_status: trust.trust_status,
208	        consecutive_failures: trust.consecutive_failures,
209	        snapshot_reason: reason,
210	        incident_id: incidentId ?? null,
211	    });
212	}
213	
214	/**
215	 * Updates agent trust score using exponential smoothing.
216	 *
217	 * Formula:
218	 *   On success: new_score = min(score × 1.03, 1.0)
219	 *               consecutive_failures reset to 0
220	 *   On failure: new_score = score × (0.9 ^ consecutive_failures)
221	 *               consecutive_failures incremented
222	 *
223	 * Status thresholds:
224	 *   score >= 0.6                       → trusted
225	 *   score 0.3–0.6                      → probation
226	 *   score 0.1–0.3 OR failures >= 5     → sandbox
227	 *   score < 0.1  OR failures >= 10     → suspended
228	 *
229	 * Cold-start prior: 0.70 (set on first DB insert by account-setup trigger).
230	 * First real outcome moves score to ~0.721 (success) or ~0.567 (failure).
231	 *
232	 * Note: scoring.ts uses a separate Bayesian (Laplace) smoothing formula for
233	 * composite action scores (computeCompositeScore). These are independent calculations.
234	 * This function uses exponential smoothing only.
235	 */
236	async function updateAgentTrust(
237	    agentId: string,
238	    customerId: string,
239	    success: boolean,
240	    actionName?: string,
241	    signalConfidence?: number | null,
242	): Promise<void> {
243	    const { data: trust } = await supabase
244	        .from('agent_trust_scores')
245	        .select('trust_id, trust_score, total_decisions, correct_decisions, consecutive_failures, trust_status')
246	        .eq('agent_id', agentId)
247	        .maybeSingle();
248	
249	    if (!trust) return;
250	
251	    const currentScore            = typeof trust.trust_score          === 'number' ? trust.trust_score          : 0.7;
252	    const currentTotalDecisions   = typeof trust.total_decisions       === 'number' ? trust.total_decisions       : 0;
253	    const currentCorrectDecisions = typeof trust.correct_decisions     === 'number' ? trust.correct_decisions     : 0;
254	    const currentFailures         = typeof trust.consecutive_failures  === 'number' ? trust.consecutive_failures  : 0;
255	    const currentStatus           = typeof trust.trust_status          === 'string'  ? trust.trust_status          : 'trusted';
256	
257	    // Always capture old values before any mutation.
258	    // These are written to every audit row so the dashboard can show
259	    // the score delta for each event in the Trust History timeline.
260	    const oldScore  = currentScore;
261	    const oldStatus = currentStatus;
262	
263	    let newScore: number;
264	    let newFailures: number;
265	    let newCorrect = currentCorrectDecisions;
266	
267	    if (success) {
268	        newFailures = 0;
269	        newCorrect += 1;
270	        // ── Phase 1: Signal confidence weighting ──────────────
271	        // High-confidence signals (e.g. Stripe webhooks, explicit SDK)
272	        // contribute the full 3% growth. Low-confidence signals (e.g.
273	        // LLM evaluation at 0.3) contribute proportionally less.
274	        // When signalConfidence is null/1.0 → 1 + 0.03*1.0 = 1.03 (unchanged).
275	        const confidence = signalConfidence ?? 1.0;
276	        newScore = Math.min(currentScore * (1 + 0.03 * confidence), 1.0);
277	    } else {
278	        // ── Coordinated Failure Interlock ──────────────────────
279	        // Check if this failure is infrastructure-attributed before
280	        // applying decay. detect_coordinated_failures() looks for 3+
281	        // agents failing the same action within the last 5 minutes.
282	        let isInfrastructureFailure = false;
283	        if (actionName) {
284	            try {
285	                const { data: coordFailures, error: coordError } = await supabase.rpc('detect_coordinated_failures', {
286	                    window_minutes: 5,
287	                    min_agent_count: 3,
288	                });
289	                if (coordError) throw new Error(coordError.message);
290	                if (coordFailures && Array.isArray(coordFailures)) {
291	                    isInfrastructureFailure = coordFailures.some(
292	                        (row: { action_name: string }) => row.action_name === actionName
293	                    );
294	                }
295	            } catch (err) {
296	                // Coordination check failed — proceed with normal decay (fail safe)
297	                console.warn('[trust] Coordinated failure check failed:', (err as Error).message);
298	            }
299	        }
300	
301	        if (isInfrastructureFailure) {
302	            snapshotTrust(agentId, trust, 'pre_incident', `coordinated:${actionName ?? 'unknown'}`).catch(() => {});
303	
304	            const { error: auditError } = await supabase.from('agent_trust_audit').insert({
305	                agent_id: agentId,
306	                customer_id: customerId,
307	                event_type: 'failure_excluded_infrastructure',
308	                old_score: oldScore,
309	                new_score: oldScore,        // score unchanged — frozen
310	                old_status: oldStatus,
311	                new_status: oldStatus,      // status unchanged — frozen
312	                reason: `Failure excluded: coordinated infrastructure failure detected on action "${actionName}". Trust score frozen.`,
313	            });
314	            if (auditError) {
315	                throw new Error(`[trust] failed to write audit event: ${auditError.message}`);
316	            }
317	            console.info('[trust] Failure excluded — coordinated infrastructure event', { agentId, actionName });
318	            return; // No trust modification
319	        }
320	
321	        // Normal agent-attributable failure: snapshot then decay
322	        snapshotTrust(agentId, trust, 'pre_failure').catch(() => {});
323	        newFailures = currentFailures + 1;
324	        newScore    = currentScore * Math.pow(0.9, newFailures);
325	    }
326	
327	    let newStatus: string;
328	    let newSuspensionReason: string | null = null;
329	
330	    if (newScore < 0.1 || newFailures >= 10) {
331	        newStatus = 'suspended';
332	        newSuspensionReason = newScore < 0.1 ? 'trust_score_critically_low' : 'consecutive_failures_exceeded';
333	    } else if (newScore < 0.3 || newFailures >= 5) {
334	        newStatus = 'sandbox';
335	        newSuspensionReason = newFailures >= 5 ? 'consecutive_failures_exceeded' : null;
336	    } else if (newScore < 0.6) {
337	        newStatus = 'probation';
338	    } else {
339	        newStatus = 'trusted';
340	    }
341	
342	    // ── ML-CHECK-2.1-B FIX: atomic trust UPDATE + audit INSERT via RPC ──
343	    // Previously: two separate supabase calls. If the audit INSERT failed,
344	    // trust score was already updated with no audit record (INVARIANT 7 violation).
345	    // Now: both ops execute inside one PL/pgSQL transaction (migration 052).
346	    // Either both succeed or both are rolled back.
347	    //
348	    // Reason format is intentional — agent.tsx parseActionFromReason()
349	    // relies on exactly these two patterns to extract the action name:
350	    //   "Outcome success via SDK: {actionName}"
351	    //   "Outcome failure recorded: {actionName}"
352	    // Status-change events append a transition note that
353	    // parseStatusLabel() in agent.tsx picks up separately.
354	
355	    const action  = actionName?.trim() || 'unknown_action';
356	    const statusChanged = oldStatus !== newStatus;
357	
358	    const baseReason = success
359	        ? `Outcome success via SDK: ${action}`
360	        : `Outcome failure recorded: ${action}`;
361	
362	    const reason = statusChanged
363	        ? `${baseReason} | Trust recalibrated: ${oldStatus} → ${newStatus}`
364	        : baseReason;
365	
366	    const { error: rpcError } = await supabase.rpc('update_trust_and_audit', {
367	        p_agent_id:             agentId,
368	        p_customer_id:          customerId,
369	        p_trust_score:          newScore,
370	        p_total_decisions:      currentTotalDecisions + 1,
371	        p_correct_decisions:    newCorrect,
372	        p_consecutive_failures: newFailures,
373	        p_trust_status:         newStatus,
374	        p_suspension_reason:    newSuspensionReason,
375	        p_updated_at:           new Date().toISOString(),
376	        p_event_type:           success ? 'success' : 'failure',
377	        p_old_score:            oldScore,
378	        p_old_status:           oldStatus,
379	        p_new_status:           newStatus,
380	        p_performed_by:         'outcome-orchestrator',
381	        p_reason:               reason,
382	    });
383	
384	    if (rpcError) {
385	        throw new Error(`[trust] atomic trust+audit update failed: ${rpcError.message}`);
386	    }
387	}
388	
389	// ── FIX: detectContextDrift — scope by customer_id ────────────
390	// BEFORE: context lookup used only issue_type with no customer_id filter.
391	// This meant Customer A's contexts were matched against Customer B's
392	// outcomes, causing false "context drift" alerts across customers.
393	//
394	// AFTER: every query is scoped by customer_id. Each customer only
395	// sees their own contexts and their own outcomes.
396	async function detectContextDrift(
397	    sb: SupabaseClient,
398	    customerId: string,
399	    contextType: string,
400	    agentId: string,
401	): Promise<void> {
402	    const { data: existingContext } = await sb
403	        .from('dim_contexts')
404	        .select('context_id')
405	        .eq('customer_id', customerId)       // FIX: was missing — caused cross-customer matches
406	        .eq('issue_type', contextType)
407	        .limit(1)
408	        .maybeSingle();
409	
410	    if (existingContext) {
411	        const { count } = await sb
412	            .from('fact_outcomes')
413	            .select('outcome_id', { count: 'exact', head: true })
414	            .eq('customer_id', customerId)
415	            .eq('context_id', existingContext.context_id);
416	
417	        if ((count ?? 0) > 0) return;
418	    }
419	
420	    const { data: recentAlert } = await sb
421	        .from('degradation_alert_events')
422	        .select('alert_id')
423	        .eq('customer_id', customerId)
424	        .eq('alert_type', 'context_drift')
425	        .gte('detected_at', new Date(Date.now() - 24 * 60 * 60 * 1000).toISOString())
426	        .limit(1);
427	
428	    if (recentAlert && recentAlert.length > 0) return;
429	
430	    await sb.from('degradation_alert_events').insert({
431	        customer_id: customerId,
432	        alert_type: 'context_drift',
433	        severity: 'warning',
434	        message: `New context type "${contextType}" encountered by agent ${agentId}. No prior outcomes for this customer. Cold-start protocol activated.`,
435	    });
436	}
437	
438	async function detectSilentFailure(
439	    sb: SupabaseClient,
440	    outcome: {
441	        outcome_id: string;
442	        customer_id: string;
443	        agent_id: string;
444	        action_id: string;
445	        action_name: string;
446	        success: boolean;
447	        outcome_score: number | null;
448	    }
449	): Promise<void> {
450	    const isSilentFailure =
451	        outcome.success === true &&
452	        outcome.outcome_score !== null &&
453	        outcome.outcome_score < 0.3;
454	
